import{_ as c,C as o,o as i,c as u,j as l,E as e,w as n,b as r,a4 as p,a3 as d,a as h}from"./chunks/framework.CS9vaShW.js";const f=JSON.parse('{"title":"A股高频行情接入链路（三）：行情接收服务器网卡与硬件入口选型","description":"比较Solarflare、NVIDIA ConnectX与FPGA定制卡在A股高频行情接收服务器中的定位、选型边界、冗余方式和测试方法。","frontmatter":{"title":"A股高频行情接入链路（三）：行情接收服务器网卡与硬件入口选型","category":"量化交易系统","tags":["高频交易","行情网卡","Solarflare","NVIDIA ConnectX","FPGA","低延迟网络"],"date":"2026-07-10T00:00:00.000Z","description":"比较Solarflare、NVIDIA ConnectX与FPGA定制卡在A股高频行情接收服务器中的定位、选型边界、冗余方式和测试方法。","wordCount":4328},"headers":[],"relativePath":"posts/a-share-market-data-infrastructure-3.md","filePath":"posts/a-share-market-data-infrastructure-3.md","lastUpdated":1784075578000}'),b={name:"posts/a-share-market-data-infrastructure-3.md"};function m(A,a,P,E,C,B){const s=o("Mermaid"),t=o("ClientOnly");return i(),u("div",null,[a[5]||(a[5]=l("p",null,"本文讨论 A 股高频行情进入 Colo 服务器时的硬件入口：网卡。重点不是简单比较厂商宣传的平均延迟，而是理解 Solarflare、NVIDIA ConnectX 和 FPGA 定制卡分别解决什么问题，以及网卡型号、端口、时间戳、PCIe、NUMA、固件和冗余结构如何共同影响行情接收链路。本文停在网卡硬件入口，不展开 RX Queue、内核旁路、用户态收包和订单簿处理。",-1)),e(t,null,{default:n(()=>[(i(),r(p,null,{default:n(()=>[e(s,{id:"mermaid-3",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20SWA%5B%E4%BA%A4%E6%8D%A2%E7%BD%91%E7%BB%9C%20A%5D%20--%3E%20NICA%5B%E7%89%A9%E7%90%86%E7%BD%91%E5%8D%A1%20A%5D%0A%20%20%20%20SWB%5B%E4%BA%A4%E6%8D%A2%E7%BD%91%E7%BB%9C%20B%5D%20--%3E%20NICB%5B%E7%89%A9%E7%90%86%E7%BD%91%E5%8D%A1%20B%5D%0A%20%20%20%20NICA%20--%3E%20PCIEA%5BPCIe%20Root%20Port%20A%5D%0A%20%20%20%20NICB%20--%3E%20PCIEB%5BPCIe%20Root%20Port%20B%5D%0A%20%20%20%20PCIEA%20--%3E%20HOST%5B%E8%A1%8C%E6%83%85%E6%8E%A5%E6%94%B6%E6%9C%8D%E5%8A%A1%E5%99%A8%5D%0A%20%20%20%20PCIEB%20--%3E%20HOST%0A%20%20%20%20CLOCK%5BPTP%20%2F%20%E6%97%B6%E9%97%B4%E6%BA%90%5D%20--%3E%20NICA%0A%20%20%20%20CLOCK%20--%3E%20NICB%0A"})]),fallback:n(()=>[...a[0]||(a[0]=[l("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[6]||(a[6]=d(`<blockquote><p>本篇范围：从交换机端口到服务器网卡和硬件平台选型。网卡之后的数据搬运、轮询、A/B 合并、Channel/Seq、补包、协议解码和订单簿构建将在后续系列讨论。</p></blockquote><h2 id="_1-网卡不是一个透明插头" tabindex="-1">1. 网卡不是一个透明插头 <a class="header-anchor" href="#_1-网卡不是一个透明插头" aria-label="Permalink to &quot;1. 网卡不是一个透明插头&quot;">​</a></h2><p>在普通业务系统中，网卡经常只按 10G、25G 或 100G 带宽选择。但高频行情主要由大量小包、突发流量和严格的尾部延迟约束组成，网卡会直接影响：</p><ul><li>小包每秒处理能力；</li><li>从物理端口到主机内存的延迟；</li><li>延迟分布和极端抖动；</li><li>突发流量下是否丢包；</li><li>硬件接收时间戳；</li><li>PTP 时钟同步；</li><li>接收队列和流量分类能力；</li><li>用户态网络栈或 DPDK 的支持；</li><li>驱动、固件和诊断工具；</li><li>A/B 双路的故障隔离程度。</li></ul><p>因此，不能只问“这张卡是多少 G”，还要问：它在目标服务器、目标驱动和真实行情包型下，是否稳定、可观测、可恢复。</p><h2 id="_2-先确定网卡在系统中的职责" tabindex="-1">2. 先确定网卡在系统中的职责 <a class="header-anchor" href="#_2-先确定网卡在系统中的职责" aria-label="Permalink to &quot;2. 先确定网卡在系统中的职责&quot;">​</a></h2><p>本文把网卡方案分成三类。</p><h3 id="_2-1-低延迟通用网卡" tabindex="-1">2.1 低延迟通用网卡 <a class="header-anchor" href="#_2-1-低延迟通用网卡" aria-label="Permalink to &quot;2.1 低延迟通用网卡&quot;">​</a></h3><p>代表：AMD Solarflare、NVIDIA ConnectX。</p><p>主要职责：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>接收以太网帧</span></span>
<span class="line"><span>→ 校验和流量分类</span></span>
<span class="line"><span>→ 硬件时间戳</span></span>
<span class="line"><span>→ DMA 到主机内存</span></span>
<span class="line"><span>→ 交给软件处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>行情含义、A/B 合并、订单簿和策略仍由 CPU 软件完成。</p><h3 id="_2-2-可编程智能网卡或fpga加速卡" tabindex="-1">2.2 可编程智能网卡或FPGA加速卡 <a class="header-anchor" href="#_2-2-可编程智能网卡或fpga加速卡" aria-label="Permalink to &quot;2.2 可编程智能网卡或FPGA加速卡&quot;">​</a></h3><p>主要职责可以扩展为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>收包</span></span>
<span class="line"><span>→ 过滤</span></span>
<span class="line"><span>→ 时间戳</span></span>
<span class="line"><span>→ 协议解析</span></span>
<span class="line"><span>→ 序号检查</span></span>
<span class="line"><span>→ A/B合并</span></span>
<span class="line"><span>→ 部分订单簿或特征计算</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>它不只是把数据交给 CPU，而是开始理解行情内容。</p><h3 id="_2-3-完整硬件交易路径" tabindex="-1">2.3 完整硬件交易路径 <a class="header-anchor" href="#_2-3-完整硬件交易路径" aria-label="Permalink to &quot;2.3 完整硬件交易路径&quot;">​</a></h3><p>更激进的 FPGA 方案可能继续完成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>行情解析</span></span>
<span class="line"><span>→ 订单簿</span></span>
<span class="line"><span>→ 信号</span></span>
<span class="line"><span>→ 风控</span></span>
<span class="line"><span>→ 订单编码与发送</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这已经不是网卡选型，而是交易系统边界重构。对第一代行情系统，不应默认从这一层开始。</p><h2 id="_3-选型之前先确认需求" tabindex="-1">3. 选型之前先确认需求 <a class="header-anchor" href="#_3-选型之前先确认需求" aria-label="Permalink to &quot;3. 选型之前先确认需求&quot;">​</a></h2><h3 id="_3-1-网络需求" tabindex="-1">3.1 网络需求 <a class="header-anchor" href="#_3-1-网络需求" aria-label="Permalink to &quot;3.1 网络需求&quot;">​</a></h3><ul><li>行情端口是 10G、25G、50G 还是更高；</li><li>A/B 是否各使用独立端口；</li><li>是否还接收快照、逐笔、指数和恢复流；</li><li>是否使用 SFP、SFP28、SFP56 或 QSFP；</li><li>是否要求光口、DAC 或 AOC；</li><li>MTU 和最大 UDP 包长；</li><li>峰值 PPS 和微突发规模。</li></ul><h3 id="_3-2-延迟需求" tabindex="-1">3.2 延迟需求 <a class="header-anchor" href="#_3-2-延迟需求" aria-label="Permalink to &quot;3.2 延迟需求&quot;">​</a></h3><p>不能只写“低延迟”，应明确测量路径：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>交换机发包时间</span></span>
<span class="line"><span>→ 网卡硬件接收时间</span></span>
<span class="line"><span>→ 数据可被软件读取的时间</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>需要观察：</p><ul><li>P50；</li><li>P99；</li><li>P99.9；</li><li>P99.99；</li><li>最大值；</li><li>行情峰值时的分布；</li><li>两路同时输入时的分布。</li></ul><p>高频系统通常更关心尾部延迟和抖动，而不是单一平均数。</p><h3 id="_3-3-时间需求" tabindex="-1">3.3 时间需求 <a class="header-anchor" href="#_3-3-时间需求" aria-label="Permalink to &quot;3.3 时间需求&quot;">​</a></h3><ul><li>是否支持硬件 RX 时间戳；</li><li>时间戳生成在 PHY、MAC 还是更后的位置；</li><li>是否支持 PTP 硬件时钟；</li><li>两张卡的时钟如何同步；</li><li>PTP 失锁时是否可检测；</li><li>时间戳与系统时钟如何关联。</li></ul><h3 id="_3-4-运维需求" tabindex="-1">3.4 运维需求 <a class="header-anchor" href="#_3-4-运维需求" aria-label="Permalink to &quot;3.4 运维需求&quot;">​</a></h3><ul><li>驱动和固件是否有长期支持；</li><li>是否能固定生产版本；</li><li>是否能读取端口、队列和错误计数；</li><li>是否有厂商诊断工具；</li><li>是否支持在线升级或需要停机；</li><li>操作系统和内核版本是否兼容；</li><li>故障卡是否容易获得同型号替换件。</li></ul><h2 id="_4-solarflare的定位" tabindex="-1">4. Solarflare的定位 <a class="header-anchor" href="#_4-solarflare的定位" aria-label="Permalink to &quot;4. Solarflare的定位&quot;">​</a></h2><p>Solarflare 目前属于 AMD 产品体系。AMD 将 Solarflare X4 定位为面向资本市场和电子交易的超低延迟以太网适配器，并提供 Onload 与 ef_vi 等软件接口。</p><h3 id="_4-1-为什么交易系统经常选择solarflare" tabindex="-1">4.1 为什么交易系统经常选择Solarflare <a class="header-anchor" href="#_4-1-为什么交易系统经常选择solarflare" aria-label="Permalink to &quot;4.1 为什么交易系统经常选择Solarflare&quot;">​</a></h3><p>Solarflare 的核心优势通常不是最高端口带宽，而是围绕低延迟电子交易形成的完整路径：</p><ul><li>小包低延迟；</li><li>较成熟的内核旁路软件；</li><li>硬件时间戳和时间同步能力；</li><li>面向交易场景的工具和调优经验；</li><li>可以从标准 Socket 逐步过渡到更低层接口；</li><li>适合专用行情接收和交易服务器。</li></ul><p>AMD 官方资料中，Onload 用于通过内核旁路加速现有网络应用，ef_vi 则是更低层的超低延迟 API。具体软件路径属于下一阶段文章，本篇只把它视为选型时的生态能力。</p><h3 id="_4-2-当前x4系列的端口形态" tabindex="-1">4.2 当前X4系列的端口形态 <a class="header-anchor" href="#_4-2-当前x4系列的端口形态" aria-label="Permalink to &quot;4.2 当前X4系列的端口形态&quot;">​</a></h3><p>AMD 当前公开的 X4 产品包括：</p><table tabindex="0"><thead><tr><th>型号</th><th>端口形态</th><th>官方列出的端口速率</th></tr></thead><tbody><tr><td>X4522</td><td>双 SFP</td><td>1/10/25/50GbE</td></tr><tr><td>X4542</td><td>双 QSFP，可拆分</td><td>双口 40/50/100GbE，或四口 1/10/25GbE</td></tr></tbody></table><p>这不表示 X4542 一定比 X4522 更适合行情。若券商提供的是 10G 或 25G 双路行情，端口形态、光模块、服务器插槽、功耗和实际延迟测试可能比最高速率更重要。</p><h3 id="_4-3-solarflare适合什么场景" tabindex="-1">4.3 Solarflare适合什么场景 <a class="header-anchor" href="#_4-3-solarflare适合什么场景" aria-label="Permalink to &quot;4.3 Solarflare适合什么场景&quot;">​</a></h3><ul><li>服务器主要用于行情和交易；</li><li>流量以 UDP 组播小包为主；</li><li>团队希望使用 Onload 或 ef_vi；</li><li>更重视低抖动和交易行业经验；</li><li>不需要复杂的 FPGA 自定义逻辑。</li></ul><h2 id="_5-nvidia-connectx的定位" tabindex="-1">5. NVIDIA ConnectX的定位 <a class="header-anchor" href="#_5-nvidia-connectx的定位" aria-label="Permalink to &quot;5. NVIDIA ConnectX的定位&quot;">​</a></h2><p>Mellanox 已属于 NVIDIA，ConnectX 是数据中心高性能以太网和 InfiniBand 适配器系列。它的定位比 Solarflare 更通用，常见于 AI、存储、云计算、RDMA、高吞吐网络和低延迟应用。</p><h3 id="_5-1-connectx的软件生态" tabindex="-1">5.1 ConnectX的软件生态 <a class="header-anchor" href="#_5-1-connectx的软件生态" aria-label="Permalink to &quot;5.1 ConnectX的软件生态&quot;">​</a></h3><p>与行情相关的常见路径包括：</p><ul><li>标准 Linux Socket；</li><li>NVIDIA XLIO；</li><li>DPDK mlx5 驱动；</li><li>更底层的 Verbs 或其他 NVIDIA 网络组件。</li></ul><p>NVIDIA 官方文档将 XLIO 描述为用户态、内核旁路的 TCP/UDP 加速库，可通过 POSIX Socket 兼容方式或更低层 API 工作。DPDK 的 mlx5 驱动则适合已经采用统一用户态轮询和内存池架构的团队。</p><h3 id="_5-2-connectx的优势" tabindex="-1">5.2 ConnectX的优势 <a class="header-anchor" href="#_5-2-connectx的优势" aria-label="Permalink to &quot;5.2 ConnectX的优势&quot;">​</a></h3><ul><li>服务器和交换网络生态广；</li><li>DPDK 支持成熟；</li><li>端口速率和型号选择丰富；</li><li>流量分类、虚拟化和卸载能力丰富；</li><li>适合统一的数据中心网络平台；</li><li>团队已有 NVIDIA/Mellanox 运维经验时，接入成本较低。</li></ul><h3 id="_5-3-connectx适合什么场景" tabindex="-1">5.3 ConnectX适合什么场景 <a class="header-anchor" href="#_5-3-connectx适合什么场景" aria-label="Permalink to &quot;5.3 ConnectX适合什么场景&quot;">​</a></h3><ul><li>公司已经统一使用 DPDK；</li><li>现有交换网络和监控体系以 NVIDIA 为主；</li><li>同一平台还承担内部高速通信、存储或计算网络；</li><li>需要较高带宽或丰富硬件流量转向；</li><li>愿意通过真实压测验证小包尾部延迟。</li></ul><h3 id="_5-4-型号越新不等于行情越快" tabindex="-1">5.4 型号越新不等于行情越快 <a class="header-anchor" href="#_5-4-型号越新不等于行情越快" aria-label="Permalink to &quot;5.4 型号越新不等于行情越快&quot;">​</a></h3><p>新一代网卡可能增加更高带宽、AI 集群、存储、安全和虚拟化功能，但这些功能不一定直接降低 10G/25G UDP 组播行情的端到端延迟。</p><p>选择时应比较：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标速率</span></span>
<span class="line"><span>目标包型</span></span>
<span class="line"><span>目标服务器</span></span>
<span class="line"><span>目标驱动和固件</span></span>
<span class="line"><span>目标用户态软件</span></span>
<span class="line"><span>目标CPU与NUMA配置</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>而不是只按 ConnectX 型号数字排序。</p><h2 id="_6-solarflare和connectx如何选择" tabindex="-1">6. Solarflare和ConnectX如何选择 <a class="header-anchor" href="#_6-solarflare和connectx如何选择" aria-label="Permalink to &quot;6. Solarflare和ConnectX如何选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Solarflare</th><th>NVIDIA ConnectX</th></tr></thead><tbody><tr><td>主要定位</td><td>电子交易和低延迟网络</td><td>通用高性能数据中心网络</td></tr><tr><td>Socket 加速</td><td>Onload</td><td>XLIO</td></tr><tr><td>低层用户态路径</td><td>ef_vi</td><td>DPDK mlx5、Ultra Socket 等</td></tr><tr><td>DPDK 统一平台</td><td>可用，但不是唯一核心</td><td>生态成熟</td></tr><tr><td>端口和高带宽范围</td><td>更聚焦</td><td>非常广</td></tr><tr><td>交易行业经验</td><td>强</td><td>强，但场景更通用</td></tr><tr><td>适合的默认场景</td><td>专用行情/交易服务器</td><td>统一高性能网络平台</td></tr></tbody></table><p>实际选型不应写成固定结论。两家网卡都可能满足高频行情需求，决定结果的经常是软件路径、服务器平台、驱动版本和团队经验。</p><h2 id="_7-fpga定制卡为什么不是高配网卡" tabindex="-1">7. FPGA定制卡为什么不是高配网卡 <a class="header-anchor" href="#_7-fpga定制卡为什么不是高配网卡" aria-label="Permalink to &quot;7. FPGA定制卡为什么不是高配网卡&quot;">​</a></h2><p>FPGA 是现场可编程门阵列。普通网卡的主要逻辑由厂商固定，而 FPGA 可以由机构自行实现数据通路。</p><h3 id="_7-1-普通低延迟网卡路径" tabindex="-1">7.1 普通低延迟网卡路径 <a class="header-anchor" href="#_7-1-普通低延迟网卡路径" aria-label="Permalink to &quot;7.1 普通低延迟网卡路径&quot;">​</a></h3>`,66)),e(t,null,{default:n(()=>[(i(),r(p,null,{default:n(()=>[e(s,{id:"mermaid-626",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20P%5B%E7%BD%91%E7%BB%9C%E5%8C%85%5D%20--%3E%20NIC%5B%E4%BD%8E%E5%BB%B6%E8%BF%9F%E7%BD%91%E5%8D%A1%5D%0A%20%20%20%20NIC%20--%3E%20PCIE%5BPCIe%20%2F%20DMA%5D%0A%20%20%20%20PCIE%20--%3E%20CPU%5BCPU%20%E8%BD%AF%E4%BB%B6%5D%0A%20%20%20%20CPU%20--%3E%20DEC%5B%E5%8D%8F%E8%AE%AE%E8%A7%A3%E7%A0%81%5D%0A%20%20%20%20DEC%20--%3E%20BOOK%5B%E8%AE%A2%E5%8D%95%E7%B0%BF%5D%0A"})]),fallback:n(()=>[...a[1]||(a[1]=[l("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[7]||(a[7]=l("h3",{id:"_7-2-fpga路径",tabindex:"-1"},[h("7.2 FPGA路径 "),l("a",{class:"header-anchor",href:"#_7-2-fpga路径","aria-label":'Permalink to "7.2 FPGA路径"'},"​")],-1)),e(t,null,{default:n(()=>[(i(),r(p,null,{default:n(()=>[e(s,{id:"mermaid-630",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20P%5B%E7%BD%91%E7%BB%9C%E5%8C%85%5D%20--%3E%20FPGA%5BFPGA%5D%0A%20%20%20%20FPGA%20--%3E%20F1%5B%E8%BF%87%E6%BB%A4%E4%B8%8E%E6%97%B6%E9%97%B4%E6%88%B3%5D%0A%20%20%20%20F1%20--%3E%20F2%5B%E5%8D%8F%E8%AE%AE%E8%A7%A3%E6%9E%90%5D%0A%20%20%20%20F2%20--%3E%20F3%5BA%2FB%E5%90%88%E5%B9%B6%E4%B8%8E%E5%BA%8F%E5%8F%B7%E6%A3%80%E6%9F%A5%5D%0A%20%20%20%20F3%20--%3E%20F4%5B%E8%AE%A2%E5%8D%95%E7%B0%BF%E6%88%96%E7%89%B9%E5%BE%81%5D%0A%20%20%20%20F4%20--%3E%20CPU%5BCPU%E6%8E%A7%E5%88%B6%E9%9D%A2%5D%0A"})]),fallback:n(()=>[...a[2]||(a[2]=[l("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[8]||(a[8]=d(`<p>FPGA 的价值不是单纯增加带宽，而是把固定、规则明确的处理变成硬件流水线，减少操作系统调度、缓存未命中和通用 CPU 路径带来的抖动。</p><h2 id="_8-fpga可以逐步卸载什么" tabindex="-1">8. FPGA可以逐步卸载什么 <a class="header-anchor" href="#_8-fpga可以逐步卸载什么" aria-label="Permalink to &quot;8. FPGA可以逐步卸载什么&quot;">​</a></h2><h3 id="_8-1-第一层-网络前置" tabindex="-1">8.1 第一层：网络前置 <a class="header-anchor" href="#_8-1-第一层-网络前置" aria-label="Permalink to &quot;8.1 第一层：网络前置&quot;">​</a></h3><ul><li>包过滤；</li><li>流量分类；</li><li>硬件时间戳；</li><li>A/B 路径标记；</li><li>原始包复制；</li><li>基础完整性检查。</li></ul><p>这类功能规则稳定，适合先做。</p><h3 id="_8-2-第二层-传输和协议处理" tabindex="-1">8.2 第二层：传输和协议处理 <a class="header-anchor" href="#_8-2-第二层-传输和协议处理" aria-label="Permalink to &quot;8.2 第二层：传输和协议处理&quot;">​</a></h3><ul><li>UDP 包切分；</li><li>PacketSeq 检查；</li><li>Channel 识别；</li><li>A/B 去重；</li><li>乱序缓存；</li><li>固定格式字段解析。</li></ul><p>协议变更会要求更新 FPGA 镜像，因此版本管理和回归测试必须严格。</p><h3 id="_8-3-第三层-订单簿和特征" tabindex="-1">8.3 第三层：订单簿和特征 <a class="header-anchor" href="#_8-3-第三层-订单簿和特征" aria-label="Permalink to &quot;8.3 第三层：订单簿和特征&quot;">​</a></h3><ul><li>新增、撤单和成交更新；</li><li>价格档位聚合；</li><li>最优买卖价；</li><li>部分订单流特征。</li></ul><p>这部分需要处理大量状态、异常恢复和内存访问，复杂度明显高于简单报文解析。</p><h3 id="_8-4-第四层-策略和发单" tabindex="-1">8.4 第四层：策略和发单 <a class="header-anchor" href="#_8-4-第四层-策略和发单" aria-label="Permalink to &quot;8.4 第四层：策略和发单&quot;">​</a></h3><ul><li>信号计算；</li><li>硬件风控；</li><li>订单编码；</li><li>直接发送。</li></ul><p>到这一层时，FPGA 已经成为交易系统核心，而不是行情网卡。任何协议或策略修改都需要硬件开发、仿真、综合、时序验证和生产发布流程。</p><h2 id="_9-fpga的主要优势与成本" tabindex="-1">9. FPGA的主要优势与成本 <a class="header-anchor" href="#_9-fpga的主要优势与成本" aria-label="Permalink to &quot;9. FPGA的主要优势与成本&quot;">​</a></h2><h3 id="_9-1-优势" tabindex="-1">9.1 优势 <a class="header-anchor" href="#_9-1-优势" aria-label="Permalink to &quot;9.1 优势&quot;">​</a></h3><ul><li>固定流水线，延迟更确定；</li><li>可以并行处理多个功能；</li><li>减少 CPU 调度和内存路径抖动；</li><li>部分场景可避免行情先经 PCIe 到 CPU 再返回网卡；</li><li>可根据自有协议和策略定制。</li></ul><h3 id="_9-2-成本" tabindex="-1">9.2 成本 <a class="header-anchor" href="#_9-2-成本" aria-label="Permalink to &quot;9.2 成本&quot;">​</a></h3><ul><li>需要 FPGA、网络和交易协议的复合团队；</li><li>调试和可观测性差于软件；</li><li>协议升级速度慢；</li><li>恢复、重建和异常状态更难实现；</li><li>硬件错误可能持续产生看似正常的错误结果；</li><li>需要软件参考实现作为校验和兜底；</li><li>生产发布需要更严格的验证流程。</li></ul><h3 id="_9-3-厂商延迟数字如何理解" tabindex="-1">9.3 厂商延迟数字如何理解 <a class="header-anchor" href="#_9-3-厂商延迟数字如何理解" aria-label="Permalink to &quot;9.3 厂商延迟数字如何理解&quot;">​</a></h3><p>AMD Alveo UL3524 等产品面向超低延迟交易，并公开给出收发器级延迟指标。这类数字通常描述特定硬件测试路径，不等于：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>行情进入</span></span>
<span class="line"><span>→ 解码</span></span>
<span class="line"><span>→ 订单簿</span></span>
<span class="line"><span>→ 策略</span></span>
<span class="line"><span>→ 风控</span></span>
<span class="line"><span>→ 订单发出</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>的完整端到端延迟。选型时必须读取测试条件，不能把收发器、网卡、应用和完整交易链路的数字混为一谈。</p><h2 id="_10-一张双口卡还是两张独立网卡" tabindex="-1">10. 一张双口卡还是两张独立网卡 <a class="header-anchor" href="#_10-一张双口卡还是两张独立网卡" aria-label="Permalink to &quot;10. 一张双口卡还是两张独立网卡&quot;">​</a></h2><p>假设 A/B 分别接在一张双口网卡的两个端口：</p>`,25)),e(t,null,{default:n(()=>[(i(),r(p,null,{default:n(()=>[e(s,{id:"mermaid-858",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20SWA%5B%E4%BA%A4%E6%8D%A2%E6%9C%BA%20A%5D%20--%3E%20P1%5B%E7%AB%AF%E5%8F%A3%201%5D%0A%20%20%20%20SWB%5B%E4%BA%A4%E6%8D%A2%E6%9C%BA%20B%5D%20--%3E%20P2%5B%E7%AB%AF%E5%8F%A3%202%5D%0A%20%20%20%20P1%20--%3E%20CARD%5B%E5%90%8C%E4%B8%80%E5%BC%A0%E5%8F%8C%E5%8F%A3%E7%BD%91%E5%8D%A1%5D%0A%20%20%20%20P2%20--%3E%20CARD%0A%20%20%20%20CARD%20--%3E%20PCIE%5B%E5%90%8C%E4%B8%80%20PCIe%20%E6%8F%92%E6%A7%BD%5D%0A"})]),fallback:n(()=>[...a[3]||(a[3]=[l("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[9]||(a[9]=l("p",null,"虽然线缆和交换机不同，但仍共享：",-1)),a[10]||(a[10]=l("ul",null,[l("li",null,"网卡芯片；"),l("li",null,"固件；"),l("li",null,"驱动实例；"),l("li",null,"PCIe 插槽；"),l("li",null,"供电；"),l("li",null,"卡级温度和硬件故障。")],-1)),a[11]||(a[11]=l("p",null,"更强的隔离方式是：",-1)),e(t,null,{default:n(()=>[(i(),r(p,null,{default:n(()=>[e(s,{id:"mermaid-897",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20SWA%5B%E4%BA%A4%E6%8D%A2%E6%9C%BA%20A%5D%20--%3E%20NICA%5B%E7%8B%AC%E7%AB%8B%E7%BD%91%E5%8D%A1%20A%5D%20--%3E%20PA%5BPCIe%20Root%20Port%20A%5D%0A%20%20%20%20SWB%5B%E4%BA%A4%E6%8D%A2%E6%9C%BA%20B%5D%20--%3E%20NICB%5B%E7%8B%AC%E7%AB%8B%E7%BD%91%E5%8D%A1%20B%5D%20--%3E%20PB%5BPCIe%20Root%20Port%20B%5D%0A"})]),fallback:n(()=>[...a[4]||(a[4]=[l("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[12]||(a[12]=d(`<p>但两张卡也会带来新的问题：</p><ul><li>PCIe 插槽是否足够；</li><li>是否位于不同 NUMA 节点；</li><li>A/B 合并时是否产生跨 NUMA 数据传输；</li><li>两张硬件时钟如何同步；</li><li>固件和驱动版本是否完全一致。</li></ul><p>因此，冗余和低延迟之间需要综合设计，不能只看卡数。</p><h2 id="_11-pcie和numa为什么属于网卡选型" tabindex="-1">11. PCIe和NUMA为什么属于网卡选型 <a class="header-anchor" href="#_11-pcie和numa为什么属于网卡选型" aria-label="Permalink to &quot;11. PCIe和NUMA为什么属于网卡选型&quot;">​</a></h2><h3 id="_11-1-pcie" tabindex="-1">11.1 PCIe <a class="header-anchor" href="#_11-1-pcie" aria-label="Permalink to &quot;11.1 PCIe&quot;">​</a></h3><p>网卡需要通过 PCIe 把数据写入主机内存。需要确认：</p><ul><li>插槽实际是 x8 还是 x16；</li><li>支持的 PCIe 代际；</li><li>是否与其他设备共享带宽；</li><li>是否经过额外 PCIe Switch；</li><li>BIOS 是否把插槽降速；</li><li>IOMMU 和虚拟化设置是否影响路径。</li></ul><h3 id="_11-2-numa" tabindex="-1">11.2 NUMA <a class="header-anchor" href="#_11-2-numa" aria-label="Permalink to &quot;11.2 NUMA&quot;">​</a></h3><p>多路服务器中，每张网卡通常更接近某个 CPU 和内存节点。理想路径是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网卡</span></span>
<span class="line"><span>→ 本地 PCIe Root Complex</span></span>
<span class="line"><span>→ 本地内存</span></span>
<span class="line"><span>→ 本地 CPU 核心</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果网卡接在 NUMA 0，而接收线程和缓冲区位于 NUMA 1，数据可能需要跨 CPU 互连，增加延迟和抖动。</p><p>但 A/B 两张卡也不一定必须分散到两个 NUMA 节点。若最终由同一个合并器处理，两路跨节点汇合也会增加成本。应通过服务器拓扑和实测决定，而不是套用固定规则。</p><h2 id="_12-硬件时间戳和ptp" tabindex="-1">12. 硬件时间戳和PTP <a class="header-anchor" href="#_12-硬件时间戳和ptp" aria-label="Permalink to &quot;12. 硬件时间戳和PTP&quot;">​</a></h2><p>网卡硬件时间戳可以在包进入硬件路径时记录时间，比应用程序调用系统时钟更接近真实到达时刻。</p><p>它可以用于：</p><ul><li>比较 A/B 路径延迟；</li><li>区分网络延迟和软件处理延迟；</li><li>分析微突发；</li><li>对齐行情和订单事件；</li><li>定位交换机到服务器的最后一段链路。</li></ul><p>需要确认：</p><ul><li>每个包是否都能获得时间戳；</li><li>时间戳点位；</li><li>时间戳分辨率与准确度；</li><li>PTP Hardware Clock 的同步方式；</li><li>两张卡是否属于同一时钟域；</li><li>PTP 失锁和主时钟切换如何上报；</li><li>时间戳溢出、跳变和缺失如何处理。</li></ul><p>“支持硬件时间戳”不等于已经具备可比较的精确时间，时钟源、拓扑和监控同样重要。</p><h2 id="_13-固件和驱动版本管理" tabindex="-1">13. 固件和驱动版本管理 <a class="header-anchor" href="#_13-固件和驱动版本管理" aria-label="Permalink to &quot;13. 固件和驱动版本管理&quot;">​</a></h2><p>同一张网卡在不同版本下可能出现：</p><ul><li>接收性能变化；</li><li>时间戳行为变化；</li><li>用户态库兼容性变化；</li><li>特定内核版本问题；</li><li>组播过滤或队列配置差异；</li><li>新功能引入新的已知缺陷。</li></ul><p>生产环境应记录：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网卡厂商与型号</span></span>
<span class="line"><span>硬件版本</span></span>
<span class="line"><span>序列号</span></span>
<span class="line"><span>固件版本</span></span>
<span class="line"><span>驱动版本</span></span>
<span class="line"><span>用户态库版本</span></span>
<span class="line"><span>操作系统与内核版本</span></span>
<span class="line"><span>BIOS版本</span></span>
<span class="line"><span>PCIe插槽和NUMA位置</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>升级流程至少包括实验室压测、历史行情回放、A/B 对比、故障注入和灰度运行。不能只因为厂商发布了“最新版本”就直接升级生产行情服务器。</p><h2 id="_14-网卡验收不能只做ping测试" tabindex="-1">14. 网卡验收不能只做ping测试 <a class="header-anchor" href="#_14-网卡验收不能只做ping测试" aria-label="Permalink to &quot;14. 网卡验收不能只做ping测试&quot;">​</a></h2><h3 id="_14-1-基础功能" tabindex="-1">14.1 基础功能 <a class="header-anchor" href="#_14-1-基础功能" aria-label="Permalink to &quot;14.1 基础功能&quot;">​</a></h3><ul><li>端口速率和链路稳定性；</li><li>组播加入；</li><li>VLAN 和 MTU；</li><li>硬件时间戳；</li><li>PTP 锁定；</li><li>驱动和诊断工具。</li></ul><h3 id="_14-2-小包性能" tabindex="-1">14.2 小包性能 <a class="header-anchor" href="#_14-2-小包性能" aria-label="Permalink to &quot;14.2 小包性能&quot;">​</a></h3><ul><li>目标 UDP 包大小；</li><li>持续 PPS；</li><li>突发 PPS；</li><li>多组播组并发；</li><li>A/B 两路同时输入；</li><li>同时开启时间戳和流量分类。</li></ul><h3 id="_14-3-延迟分布" tabindex="-1">14.3 延迟分布 <a class="header-anchor" href="#_14-3-延迟分布" aria-label="Permalink to &quot;14.3 延迟分布&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P50</span></span>
<span class="line"><span>P99</span></span>
<span class="line"><span>P99.9</span></span>
<span class="line"><span>P99.99</span></span>
<span class="line"><span>最大值</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>必须在空载、稳定高负载、微突发、CPU 干扰和两路同时输入条件下测试。</p><h3 id="_14-4-丢包和恢复场景" tabindex="-1">14.4 丢包和恢复场景 <a class="header-anchor" href="#_14-4-丢包和恢复场景" aria-label="Permalink to &quot;14.4 丢包和恢复场景&quot;">​</a></h3><ul><li>RX 缓冲压力；</li><li>单路断线；</li><li>链路频繁上下线；</li><li>组播成员变化；</li><li>PTP 失锁；</li><li>固件重置；</li><li>网卡温度升高；</li><li>PCIe 错误；</li><li>一张卡故障后另一张卡是否仍稳定。</li></ul><h3 id="_14-5-可复现性" tabindex="-1">14.5 可复现性 <a class="header-anchor" href="#_14-5-可复现性" aria-label="Permalink to &quot;14.5 可复现性&quot;">​</a></h3><p>每次测试都应记录完整环境，避免比较两个“名字相同但配置不同”的结果：</p><ul><li>服务器型号；</li><li>CPU 和 BIOS；</li><li>内存与 NUMA；</li><li>网卡插槽；</li><li>固件、驱动和软件；</li><li>交换机和光模块；</li><li>流量发生器；</li><li>包长、速率、突发模型；</li><li>测量时钟和统计方法。</li></ul><h2 id="_15-一个实用的选择路径" tabindex="-1">15. 一个实用的选择路径 <a class="header-anchor" href="#_15-一个实用的选择路径" aria-label="Permalink to &quot;15. 一个实用的选择路径&quot;">​</a></h2><h3 id="_15-1-第一代系统" tabindex="-1">15.1 第一代系统 <a class="header-anchor" href="#_15-1-第一代系统" aria-label="Permalink to &quot;15.1 第一代系统&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Solarflare 或 ConnectX</span></span>
<span class="line"><span>+ 两张独立物理卡</span></span>
<span class="line"><span>+ CPU 软件完成行情处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>目标是先建立：</p><ul><li>完整、可验证的行情接入；</li><li>原始数据留存；</li><li>A/B 路径监控；</li><li>软件订单簿参考实现；</li><li>可复现的延迟和丢包测试。</li></ul><h3 id="_15-2-第二阶段" tabindex="-1">15.2 第二阶段 <a class="header-anchor" href="#_15-2-第二阶段" aria-label="Permalink to &quot;15.2 第二阶段&quot;">​</a></h3><p>根据团队生态选择：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Solarflare → Onload / ef_vi</span></span>
<span class="line"><span>ConnectX → XLIO / DPDK mlx5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>再优化 CPU 隔离、NUMA、内存、队列和用户态数据路径。</p><h3 id="_15-3-第三阶段" tabindex="-1">15.3 第三阶段 <a class="header-anchor" href="#_15-3-第三阶段" aria-label="Permalink to &quot;15.3 第三阶段&quot;">​</a></h3><p>只把已经证明稳定、规则明确且真正成为瓶颈的部分卸载到 FPGA：</p><ul><li>时间戳；</li><li>包过滤；</li><li>A/B 去重；</li><li>固定协议解析；</li><li>部分特征计算。</li></ul><p>完整硬件订单簿或策略应在软件参考实现、异常恢复方案和硬件验证体系成熟后再考虑。</p><h2 id="_16-选择矩阵" tabindex="-1">16. 选择矩阵 <a class="header-anchor" href="#_16-选择矩阵" aria-label="Permalink to &quot;16. 选择矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需求</th><th>选择倾向</th></tr></thead><tbody><tr><td>专用行情和交易服务器</td><td>Solarflare 或经过实测的 ConnectX</td></tr><tr><td>团队已有 Onload/ef_vi 经验</td><td>Solarflare</td></tr><tr><td>团队已有 DPDK/MLX5 体系</td><td>ConnectX</td></tr><tr><td>需要统一数据中心网络生态</td><td>ConnectX</td></tr><tr><td>需要固定流水线和极低抖动</td><td>FPGA</td></tr><tr><td>协议和策略经常修改</td><td>CPU 软件方案</td></tr><tr><td>没有 FPGA 开发与验证团队</td><td>不选择完整 FPGA 路径</td></tr><tr><td>要降低单卡故障影响</td><td>A/B 使用两张独立网卡</td></tr><tr><td>只依据厂商平均延迟做决定</td><td>不足，必须实测尾部延迟</td></tr></tbody></table><h2 id="_17-仍需确认的问题" tabindex="-1">17. 仍需确认的问题 <a class="header-anchor" href="#_17-仍需确认的问题" aria-label="Permalink to &quot;17. 仍需确认的问题&quot;">​</a></h2><ul><li>券商提供的端口速率和光模块类型；</li><li>峰值 PPS 与微突发模型；</li><li>最大 UDP 包长度和 MTU；</li><li>是否要求硬件时间戳；</li><li>PTP 主时钟和交换机拓扑；</li><li>服务器 PCIe 与 NUMA 结构；</li><li>操作系统、驱动和固件支持周期；</li><li>A/B 是否要求卡级物理隔离；</li><li>是否已有 Onload、XLIO 或 DPDK 技术栈；</li><li>FPGA 计划卸载到哪一层；</li><li>端到端延迟目标和测量方法。</li></ul><p>没有这些信息，无法仅根据厂商和型号给出可靠结论。</p><h2 id="_18-后续文章" tabindex="-1">18. 后续文章 <a class="header-anchor" href="#_18-后续文章" aria-label="Permalink to &quot;18. 后续文章&quot;">​</a></h2><p>前三篇已经把行情从交易所一路讲到服务器网卡入口。后续系列将进入行情程序：</p><ol><li>网卡 RX Queue、RX Ring、DMA 与 CPU；</li><li>Linux Socket、Onload、ef_vi、XLIO 和 DPDK；</li><li>A/B 双路接收与消息去重；</li><li>Channel、Seq、乱序窗口和丢包恢复；</li><li>协议解码和逐笔事件标准化；</li><li>本地订单簿构建与可信状态；</li><li>行情异常时的策略降级和交易保护。</li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://www.amd.com/en/products/ethernet-adapters/solarflare-x4.html" target="_blank" rel="noreferrer">AMD Solarflare X4 Ethernet Adapters</a></li><li><a href="https://www.amd.com/en/support/downloads/solarflare-downloads.html/ethernet-adapters/solarflare/x4-series.html" target="_blank" rel="noreferrer">AMD Solarflare X4 Support：Onload 与 ef_vi</a></li><li><a href="https://docs.nvidia.com/networking/display/xliov361/introduction-to-xlio" target="_blank" rel="noreferrer">NVIDIA XLIO Documentation</a></li><li><a href="https://doc.dpdk.org/guides/nics/mlx5.html" target="_blank" rel="noreferrer">DPDK NVIDIA MLX5 Ethernet Driver</a></li><li><a href="https://www.amd.com/en/products/accelerators/alveo/ul3524.html" target="_blank" rel="noreferrer">AMD Alveo UL3524</a></li></ul><blockquote><p>本文仅为个人学习笔记和系统架构设计整理，不构成任何投资建议或交易建议。高频量化交易系统涉及市场风险、技术风险、合规风险和运维风险，任何实盘部署都应经过充分测试、独立验证和风险评估。</p></blockquote>`,62))])}const D=c(b,[["render",m]]);export{f as __pageData,D as default};
